            'nav.toggleTheme': 'Toggle Theme',
            'nav.parseMeta': 'Batch Detect Metadata + Generate Thumbnails',
            'nav.toggleOverlay': 'Hide/Show Card Icons & Text',
            'nav.search': 'Search...',
            'nav.import': 'Import (ZIP)',
            'nav.export': 'Export (ZIP)',
            'sidebar.workspace': 'Workspace',
            'sidebar.addCategory': '➕ Add Category',
            'sidebar.gallery': '🖼️ Gallery',
            'sidebar.masonry': '📌 Masonry',
            'sidebar.list': '📄 List',
            'modal.editTitle': 'Edit Prompt',
            'modal.titleLabel': 'Title',
            'modal.contentLabel': 'Content',
            'modal.tagsLabel': 'Tags (comma-separated)',
            'modal.naiParams': 'NAI Parameters',
            'modal.parseMetaBtn': '🔍 Detect Metadata',
            'modal.negPrompt': 'Negative Prompt',
