            'modal.clickOrDrag': 'Click or drag image here',
            'modal.removeImage': 'Remove Image',
            'modal.saveImage': '💾 Download Original',
            'modal.copyImage': '📋 Copy to Clipboard',
            'modal.sendNAI': '📤 Send to NAI',
            'modal.cancel': 'Cancel',
            'modal.saveChanges': 'Save Changes',
            'settings.langLabel': 'Language',
            'settings.scaleLabel': 'Scale',
            'settings.cardWidthLabel': 'Card Width',
            'settings.slotTitle': '💾 Save Slots',
            'settings.saveSlot': 'Save to New Slot',
